1329→    private fun ASTNode.isRawStringLiteralFunctionBodyExpression() =
1330→        (prevLeaf()?.elementType != WHITE_SPACE || prevLeaf()?.text == " ") &&
1331→            FUN ==
1332→            prevCodeLeaf()
1333→                .takeIf { it?.elementType == EQ }
1334→                ?.treeParent
1335→                ?.elementType
